import React from "react";
import { connect } from "react-redux";
import {
  onPostChangecreateActin,
  addPostcreateActin,
} from "../../redux/messegData-reducer";
import Contacts from "./Contacts";

/*const ContactsContainer = (props) => {
  const addPost = () => {
    props.dispatch(addPostcreateActin());
  };

  const onPostChange = (e) => {
    props.dispatch(onPostChangecreateActin(e));
  };

  return (
    <Contacts
      onPost={onPostChange}
      addPost={addPost}
      messege={props.store.messeges.messegData}
      newMessege={props.store.messeges.newChanges}
    />
  );
};

export default ContactsContainer;*/

let mapStateToProps = (state) => {
  return {
    messege: state.messeges,
  };
};
let mapDispatchToProps = (store) => {
  return {
    onPost: (e) => {
      store.dispatch(onPostChangecreateActin(e));
    },
    addPost: () => {
      store.dispatch(addPostcreateActin());
    },
  };
};

const ContactsContainer = connect(
  mapStateToProps,
  mapDispatchToProps
)(Contacts);
